/**
 * Calculates the result of a percentage operation.
 *
 * @param {number} base - The base value.
 * @param {number} percentage - The percentage value.
 * @param {string} operation - The operation to perform. Can be 'increase' or 'decrease'.
 * @return {number} The result of the operation.
 */
function calculatePercentage(base, percentage, operation) {
  if (operation === 'increase') {
    const result = (base / 100) * percentage + base;
    return result;
  } else if (operation === 'decrease') {
    const result = (base - (base / 100) * percentage);
    return result;
  } else {
    throw new Error('Invalid operation. Must be either "increase" or "decrease".');
  }
}

